create table dirkspzm32.isi_res_pruef_plan_artikel_val (
    sid                       varchar2(2 char) not null enable,
    firma_nr                  number(6, 0) not null enable,
    res_id                    number(*, 0) not null enable,
    res_teilgewerk            number(*, 5) not null enable,
    res_pruef_plan_nr         varchar2(100 char) not null enable,
    res_pruef_plan_data_nr    number(*, 5) not null enable,
    res_pruef_plan_data_value varchar2(100 char) not null enable,
    res_pruef_plan_data_type  varchar2(10 char) not null enable,
    created_date              date not null enable,
    created_login_id          number(*, 0),
    last_change_date          date,
    last_change_login_id      number(*, 0)
);

alter table dirkspzm32.isi_res_pruef_plan_artikel_val
    add constraint isi_res_pruef_plan_artikel_val
        primary key ( res_id,
                      res_teilgewerk,
                      res_pruef_plan_nr,
                      res_pruef_plan_data_nr,
                      firma_nr,
                      sid )
            using index enable;


